#include <stdio.h>
#include <string.h>
int main(){
    int T; if(scanf("%d", &T)!=1) return 0;
    while(T--){
        long long X; char s[20];
        scanf("%lld", &X);
        scanf("%s", s);
        long long c=0,n=0,d=0;
        for(int i=0; s[i]; ++i){
            if(s[i]=='C') c++;
            else if(s[i]=='N') n++;
            else if(s[i]=='D') d++;
        }
        long long car = 2*c + d;
        long long chef = 2*n + d;
        long long prize;
        if(car>chef) prize = 60*X;
        else if(car<chef) prize = 40*X;
        else prize = 55*X;
        printf("%lld", prize);
        if(T) printf("\n");
    }
    return 0;
}

